// Destinatários do agente comparativo313 — somente compradores:
//   - funcao === 'comprador'
//   - 'comparativo313' no array `agentes` (Firestore users)
//   - whatsapp válido (não vazio, não '0', mais de 5 chars)
return items
  .map(it => ({
    json: {
      email_login: (it.json.id || it.json.email_login || '').toLowerCase(),
      nome:        it.json.nome,
      funcao:      it.json.funcao,
      agentes:     it.json.agentes,
      whatsapp:    String(it.json.whatsapp || '').trim(),
    }
  }))
  .filter(it => {
    const d = it.json;
    return d.funcao === 'comprador'
      && Array.isArray(d.agentes) && d.agentes.includes('comparativo313')
      && d.whatsapp && d.whatsapp !== '0' && d.whatsapp.length > 5
      && d.email_login;
  });

// Cruza compradores com (a) o resumo agregado por responsável e
// (b) o drill por filial. Sai 1 item por comprador com seus dados.
const compradores = $('Filtrar compradores').all().map(it => it.json);
const resumoResp  = $('Supabase: resumo por responsavel').all().map(it => it.json);
const drill       = $('Supabase: drill por filial').all().map(it => it.json);

function matchByEmail(arr, email) {
  if (!email) return null;
  return arr.find(r => String(r.usuario_email_login || '').toLowerCase() === email) || null;
}

return compradores.map(c => {
  const resumo = matchByEmail(resumoResp, c.email_login);
  const porFilial = resumo
    ? drill.filter(d => String(d.usuario_id) === String(resumo.usuario_id))
           .filter(d => Number(d.rupturas_pendentes || 0) > 0)
           .sort((a, b) => Number(b.rupturas_pendentes) - Number(a.rupturas_pendentes))
    : [];
  return {
    json: {
      email_login: c.email_login,
      nome:        c.nome,
      whatsapp:    c.whatsapp,
      rupturas_pendentes: Number(resumo?.rupturas_pendentes || 0),
      filiais_afetadas:   Number(resumo?.filiais_afetadas || 0),
      por_filial: porFilial,
    }
  };
});

// Mensagem do comprador — totais + breakdown por filial (top 5).
const u = $input.first().json;

function num(v) {
  if (v == null) return '—';
  return Number(v).toLocaleString('pt-BR', { maximumFractionDigits: 0 });
}

const total      = u.rupturas_pendentes;
const filiais    = u.filiais_afetadas;
const porFilial  = (u.por_filial || []).slice(0, 5);

const linhasFiliais = porFilial.length
  ? porFilial.map(f => `   • *${f.filial_cod}* — ${num(f.rupturas_pendentes)} ruptura(s)`).join('\n')
  : '';

const maisRecente = (u.por_filial || []).reduce((acc, f) => {
  const d = f.ultima_deteccao ? new Date(f.ultima_deteccao).getTime() : 0;
  return d > acc ? d : acc;
}, 0);
const dataDeteccao = maisRecente ? new Date(maisRecente).toLocaleDateString('pt-BR') : '';

const link = $env.APP_URL_COMP313 || 'http://margem.interno/agente/comparativo313';

const topInfo  = porFilial.length
  ? `\n\nPrincipais filiais com ruptura:\n${linhasFiliais}`
  : '';
const extras = (u.por_filial || []).length > porFilial.length
  ? `\n   …e mais ${u.por_filial.length - porFilial.length} filial(is).`
  : '';

const message = `Olá, *${u.nome}*!\n\nResumo *Comparativo 313* — depósito 313 tem estoque que está em falta na loja para as suas seções:\n\nVocê tem *${num(total)}* ruptura(s) abertas em ${num(filiais)} filial(is).${topInfo}${extras}${dataDeteccao ? `\n\n_Última detecção: ${dataDeteccao}_` : ''}\n\nAcesse: ${link}`;

return [{
  json: {
    phone:       u.whatsapp,
    message,
    email_login: u.email_login,
  }
}];
